    {
        double abs = Math.Abs(_bytes);
        if (abs >= BytesInTerabyte) return (Terabytes, TerabyteSymbol);
        if (abs >= BytesInGigabyte) return (Gigabytes, GigabyteSymbol);
        if (abs >= BytesInMegabyte) return (Megabytes, MegabyteSymbol);
